#include <iostream>
#include <string>
using namespace std;
bool solve(string s, string t) {
    if (s.size()!=t.size()) return false;
    int cnt[26]={0};
    for (char c:s) cnt[c-'a']++;
    for (char c:t) cnt[c-'a']--;
    for (int i=0;i<26;i++) if(cnt[i]!=0) return false;
    return true;
}
int main() {
    string s,t;
    if(getline(cin,s)&&getline(cin,t))
        cout<<(solve(s,t)?"true":"false")<<endl;
    return 0;
}

