const fs = require('fs');
function solve(s,t) {
    if(s.length!==t.length) return false;
    const cnt=new Array(26).fill(0);
    for(const c of s) cnt[c.charCodeAt(0)-97]++;
    for(const c of t) cnt[c.charCodeAt(0)-97]--;
