#include <stdio.h>
#include <string.h>
#include <stdbool.h>
bool solve(char*s,char*t){
    if(strlen(s)!=strlen(t)) return false;
    int cnt[26]={0};
    for(int i=0;s[i];i++) cnt[s[i]-'a']++;
    for(int i=0;t[i];i++) cnt[t[i]-'a']--;
    for(int i=0;i<26;i++) if(cnt[i]) return false;
    return true;
}
int main(){
    char s[50001],t[50001];
    if(fgets(s,sizeof(s),stdin)&&fgets(t,sizeof(t),stdin)){
        s[strcspn(s,"\n")]=0;t[strcspn(t,"\n")]=0;
        printf("%s\n",solve(s,t)?"true":"false");
    }
    return 0;
}
